import {
  BnGovernanceConfig,
  BnGovernanceOutboundResult,
} from '@binom/sdk-governance/types';
import { sanitize } from './bn-governance-core';

/** Append governance rules to a sanitized user prompt (does not alter app role prompts). */
export function appendGovernanceRules(sanitized: string, rules: string): string {
  const body = sanitized.trim();
  const governanceRules = rules.trim();

  if (!governanceRules) {
    return body;
  }
  if (!body) {
    return governanceRules;
  }
  return `${body}\n\n${governanceRules}`;
}

/** Sanitize PII and append governance rules for outbound LLM user messages. */
export function buildOutboundUserMessage(
  input: string,
  rules: string,
  config?: Partial<BnGovernanceConfig>,
): BnGovernanceOutboundResult {
  const result = sanitize(input, config);
  const outbound = appendGovernanceRules(result.text, rules);

  return {
    ...result,
    outbound,
  };
}
