import {
  BN_GOVERNANCE_PLACEHOLDER_TYPE_MAP,
  BnGovernanceDetectorId,
  BnGovernanceFinding,
  BnGovernancePlaceholderType,
} from '@binom/sdk-governance/types';

export function resolvePlaceholderType(
  detectorType: BnGovernanceDetectorId | string,
): BnGovernancePlaceholderType | string {
  if (detectorType in BN_GOVERNANCE_PLACEHOLDER_TYPE_MAP) {
    return BN_GOVERNANCE_PLACEHOLDER_TYPE_MAP[detectorType as BnGovernanceDetectorId];
  }
  return String(detectorType).toUpperCase();
}

export function buildPlaceholderToken(
  finding: BnGovernanceFinding,
  format: string,
  key: string,
  index: number,
): string {
  const typeLabel = resolvePlaceholderType(finding.type);
  return format
    .replace(/\{\{TYPE\}\}/g, typeLabel)
    .replace(/\{\{KEY\}\}/g, key)
    .replace(/\{\{index\}\}/g, String(index));
}
