import {
  BN_GOVERNANCE_DEFAULT_CONFIG,
  BnGovernanceConfig,
  BnGovernanceDetectorId,
  BnGovernanceFinding,
  BnGovernanceMapping,
  BnGovernanceRestoreOptions,
  BnGovernanceResult,
} from '@binom/sdk-governance/types';
import { getRegisteredDetectors } from '@binom/sdk-governance/registry';
import {
  getDetectorOptions,
  isDetectorEnabled,
  mergeConfig,
  resetFindingCounter,
} from '@binom/sdk-governance/detectors';
import { BnPlaceholderSession } from './placeholder/bn-placeholder-session';
import {
  createMappingId,
  isMappingExpired,
  resolvePlaceholderFormat,
} from './placeholder/bn-governance-mapping-utils';

function resolveConfig(config?: Partial<BnGovernanceConfig>): BnGovernanceConfig {
  return mergeConfig(BN_GOVERNANCE_DEFAULT_CONFIG, config);
}

function overlaps(a: BnGovernanceFinding, b: BnGovernanceFinding): boolean {
  return a.start < b.end && b.start < a.end;
}

function resolveOverlaps(
  findings: BnGovernanceFinding[],
  strategy: BnGovernanceConfig['overlapStrategy'],
  detectors: Map<string, number>,
): BnGovernanceFinding[] {
  const sorted = [...findings].sort((a, b) => {
    if (strategy === 'priority') {
      const priorityDiff = (detectors.get(b.type) ?? 0) - (detectors.get(a.type) ?? 0);
      if (priorityDiff !== 0) {
        return priorityDiff;
      }
    }
    const lengthDiff = b.end - b.start - (a.end - a.start);
    if (lengthDiff !== 0) {
      return lengthDiff;
    }
    return a.start - b.start;
  });

  const accepted: BnGovernanceFinding[] = [];
  for (const finding of sorted) {
    const hasOverlap = accepted.some((existing) => overlaps(existing, finding));
    if (!hasOverlap) {
      accepted.push(finding);
    }
  }

  return accepted.sort((a, b) => a.start - b.start);
}

function maskValue(finding: BnGovernanceFinding, maskChar: string): string {
  const { value, type } = finding;
  switch (type) {
    case 'email': {
      const [local, domain] = value.split('@');
      if (!domain) {
        return maskChar.repeat(value.length);
      }
      const visible = local.slice(0, 1);
      return `${visible}${maskChar.repeat(Math.max(local.length - 1, 1))}@${domain}`;
    }
    case 'creditCard':
    case 'iban': {
      const visible = value.slice(-4);
      return `${maskChar.repeat(Math.max(value.length - 4, 0))}${visible}`;
    }
    case 'phone': {
      const digits = value.replace(/\D/g, '');
      const visible = digits.slice(-2);
      return value.replace(/\d/g, maskChar).replace(new RegExp(`${maskChar}{2}$`), visible);
    }
    default:
      if (value.length <= 2) {
        return maskChar.repeat(value.length);
      }
      return `${value[0]}${maskChar.repeat(value.length - 2)}${value[value.length - 1]}`;
  }
}

function buildEmptyResult(
  text: string,
  placeholderFormat: string,
  createdAt: string,
  expiresAt?: string,
): BnGovernanceResult {
  return {
    text,
    output: text,
    findings: [],
    mapping: {
      id: createMappingId(),
      placeholders: {},
      meta: {
        createdAt,
        expiresAt,
        detectorIds: [],
        placeholderFormat,
      },
    },
    placeholderFormat,
    createdAt,
    expiresAt,
  };
}

function resolveMapping(
  mappingOrId: BnGovernanceMapping | string,
  options?: BnGovernanceRestoreOptions,
): BnGovernanceMapping | undefined {
  if (typeof mappingOrId === 'string') {
    return options?.store?.get(mappingOrId);
  }
  return mappingOrId;
}

export function detect(
  input: string,
  config?: Partial<BnGovernanceConfig>,
): BnGovernanceFinding[] {
  if (!input || typeof input !== 'string') {
    return [];
  }

  resetFindingCounter();
  const resolved = resolveConfig(config);
  const detectors = getRegisteredDetectors();
  const priorityMap = new Map(detectors.map((d) => [d.id, d.priority]));
  const findings: BnGovernanceFinding[] = [];

  for (const detector of detectors) {
    const id = detector.id as BnGovernanceDetectorId;
    if (!isDetectorEnabled(resolved.detectors, id)) {
      continue;
    }
    const options = getDetectorOptions(resolved.detectors, id);
    const minConfidence = options?.minConfidence ?? 0;
    const detected = detector.detect(input, options).filter(
      (f) => f.confidence >= minConfidence,
    );
    findings.push(...detected);
  }

  return resolveOverlaps(findings, resolved.overlapStrategy ?? 'longest', priorityMap);
}

export function sanitize(
  input: string,
  config?: Partial<BnGovernanceConfig>,
): BnGovernanceResult {
  const resolved = resolveConfig(config);
  const placeholderFormat = resolvePlaceholderFormat(resolved);
  const createdAt = new Date().toISOString();
  const expiresAt = resolved.mappingTtlMs
    ? new Date(Date.parse(createdAt) + resolved.mappingTtlMs).toISOString()
    : undefined;

  if (!input || typeof input !== 'string') {
    return buildEmptyResult(input ?? '', placeholderFormat, createdAt, expiresAt);
  }

  const findings = detect(input, resolved);
  const placeholders: Record<string, string> = {};
  const session = new BnPlaceholderSession(
    placeholderFormat,
    resolved.reusePlaceholders ?? true,
  );
  let text = input;

  const sorted = [...findings].sort((a, b) => b.start - a.start);
  for (const finding of sorted) {
    const placeholder = session.createPlaceholder(finding);
    finding.placeholder = placeholder;
    placeholders[placeholder] = finding.value;
    text = text.slice(0, finding.start) + placeholder + text.slice(finding.end);
  }

  const mapping: BnGovernanceMapping = {
    id: createMappingId(),
    placeholders,
    meta: {
      createdAt,
      expiresAt,
      detectorIds: [...new Set(findings.map((f) => f.type))],
      placeholderFormat,
    },
  };

  if (resolved.mappingStore) {
    resolved.mappingStore.save(mapping);
  }

  return {
    text,
    output: text,
    findings: [...findings].sort((a, b) => a.start - b.start),
    mapping,
    placeholderFormat,
    createdAt,
    expiresAt,
  };
}

export function mask(
  input: string,
  config?: Partial<BnGovernanceConfig>,
): BnGovernanceResult {
  const resolved = resolveConfig(config);
  const placeholderFormat = resolvePlaceholderFormat(resolved);
  const createdAt = new Date().toISOString();
  const expiresAt = resolved.mappingTtlMs
    ? new Date(Date.parse(createdAt) + resolved.mappingTtlMs).toISOString()
    : undefined;

  if (!input || typeof input !== 'string') {
    return buildEmptyResult(input ?? '', placeholderFormat, createdAt, expiresAt);
  }

  const findings = detect(input, resolved);
  const maskChar = resolved.maskChar ?? '*';
  let text = input;

  const sorted = [...findings].sort((a, b) => b.start - a.start);
  for (const finding of sorted) {
    const masked = maskValue(finding, maskChar);
    text = text.slice(0, finding.start) + masked + text.slice(finding.end);
  }

  return {
    text,
    output: text,
    findings,
    mapping: {
      id: createMappingId(),
      placeholders: {},
      meta: {
        createdAt,
        expiresAt,
        detectorIds: [...new Set(findings.map((f) => f.type))],
        placeholderFormat,
      },
    },
    placeholderFormat,
    createdAt,
    expiresAt,
  };
}

export function restore(
  input: string,
  mappingOrId: BnGovernanceMapping | string,
  options?: BnGovernanceRestoreOptions,
): string {
  if (!input) {
    return input ?? '';
  }

  const mapping = resolveMapping(mappingOrId, options);
  if (!mapping?.placeholders) {
    return input;
  }

  if (isMappingExpired(mapping)) {
    return input;
  }

  let output = input;
  const keys = Object.keys(mapping.placeholders).sort((a, b) => b.length - a.length);
  for (const key of keys) {
    output = output.split(key).join(mapping.placeholders[key]);
  }
  return output;
}
