import { BnGovernanceFinding } from '@binom/sdk-governance/types';
import { buildPlaceholderToken } from './bn-placeholder-builder';
import { generatePlaceholderKey } from './bn-placeholder-key';

export class BnPlaceholderSession {
  private readonly reuse: boolean;
  private readonly format: string;
  private readonly reuseCache = new Map<string, string>();
  private index = 1;

  constructor(format: string, reusePlaceholders = true) {
    this.format = format;
    this.reuse = reusePlaceholders;
  }

  createPlaceholder(finding: BnGovernanceFinding): string {
    const cacheKey = `${finding.type}::${finding.value}`;
    if (this.reuse) {
      const cached = this.reuseCache.get(cacheKey);
      if (cached) {
        return cached;
      }
    }

    const key = generatePlaceholderKey();
    const placeholder = buildPlaceholderToken(finding, this.format, key, this.index);
    this.index += 1;

    if (this.reuse) {
      this.reuseCache.set(cacheKey, placeholder);
    }

    return placeholder;
  }
}
